    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  // Detail View State
  const [updateDate, setUpdateDate] = useState<string>(getLocalDate());
  const [updateContent, setUpdateContent] = useState('');
  const [isPolishing, setIsPolishing] = useState(false);
  const [historySort, setHistorySort] = useState<SortOrder>('NEWEST');
  const [editUpdateId, setEditUpdateId] = useState<string | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  // Profile View State
  const [newPin, setNewPin] = useState('');
  const [confirmPin, setConfirmPin] = useState('');
  const [profileMessage, setProfileMessage] = useState<{type: 'success'|'error', text: string} | null>(null);

  // Chat State
  const [chatMessages, setChatMessages] = useState<{role: 'user' | 'model', text: string}[]>([
     { role: 'model', text: "Hi! I'm your AI assistant. I can answer questions about your tasks and team updates." }
  ]);
  const [chatInput, setChatInput] = useState('');
  const [isChatLoading, setIsChatLoading] = useState(false);
  chatEndRef = useRef<HTMLDivElement>(null);

  const [lastStatus, setLastStatus] = useState<TaskStatus>(TaskStatus.NOT_YET);

  // Voice Recorder State
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessingVoice, setIsProcessingVoice] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);

  // --- Initialization ---

  useEffect(() => {
    // Check for logged in user
    const checkUser = async () => {
        const user = await getCurrentUser();
        if (user) {
          setCurrentUser(user);
          loadData();
        }
    };
    checkUser();
  }, []);

  useEffect(() => {
    if (activeTab === 'chat') {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages, activeTab]);

  const loadData = async () => {
    setIsLoadingData(true);
    const [fetchedTasks, fetchedUpdates, fetchedUsers] = await Promise.all([
        getTasks(),
        getUpdates(),
        getUsers()
    ]);
    setTasks(fetchedTasks);
    setUpdates(fetchedUpdates);
    setAllUsers(fetchedUsers);
    setIsLoadingData(false);
  };

  // Reset form when switching tasks
  useEffect(() => {
    if (selectedTaskId) {
      setUpdateContent('');
      setUpdateDate(getLocalDate());
      setEditUpdateId(null);
      setIsPolishing(false);

      const t = tasks.find(x => x.id === selectedTaskId);
      if (t) {
        setLastStatus(t.status);
      }
    }
  }, [selectedTaskId]);

  // --- Auth Actions ---

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthLoading(true);
    const user = await loginUser(authUsername, authPin);
    if (user) {
      setCurrentUser(user);
      await loadData();
      setAuthError('');
      setAuthUsername('');
      setAuthPin('');
    } else {
      setAuthError('Invalid username or PIN');
    }
    setAuthLoading(false);
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (authPin.length < 4) {
      setAuthError('PIN must be at least 4 digits');
      return;
    }
    setAuthLoading(true);
    const user = await registerUser(authUsername, authPin, authRole);
    if (user) {
      setCurrentUser(user);
      await loadData();
      setAuthError('');
      setAuthUsername('');
      setAuthPin('');
    } else {
      setAuthError('Username already exists');
    }
    setAuthLoading(false);
  };

  const handleLogout = () => {
    logoutUser();
    setCurrentUser(null);
    setTasks([]);
    setUpdates([]);
    setSelectedTaskId(null);
    setActiveTab('overview');
    setFilterUser('ALL_TEAM');
  };

  const handleUpdateProfile = async () => {
    if (!currentUser) return;
    setProfileMessage(null);

    if (newPin.length < 4) {
      setProfileMessage({ type: 'error', text: 'PIN must be at least 4 digits.' });
      return;
    }
    if (newPin !== confirmPin) {
      setProfileMessage({ type: 'error', text: 'PINs do not match.' });
      return;
    }

    const updatedUser = { ...currentUser, pin: newPin };
    const success = await updateUser(updatedUser);

    if (success) {
      setCurrentUser(updatedUser);
      setProfileMessage({ type: 'success', text: 'PIN updated successfully!' });
      setNewPin('');
      setConfirmPin('');
    } else {
      setProfileMessage({ type: 'error', text: 'Failed to update profile.' });
