         <button onClick={() => setActiveTab('profile')} className={`flex-1 flex flex-col items-center justify-center gap-1 ${activeTab === 'profile' ? 'text-primary' : 'text-stone-300'}`}>
            <UserIcon size={20} /> <span className="text-[10px] font-bold">Profile</span>
         </button>
      </div>
    </div>
  );
};

