import { GoogleGenAI, Type } from "@google/genai";
import { CATEGORIES, STATUSES } from '../constants';

/**
 * Creates a new instance of GoogleGenAI using the API key from environment variables.
 * Initialized with a named parameter as per the latest SDK requirements.
 */
const getAIClient = () => {
  if (!process.env.API_KEY) {
    console.warn("Gemini API Key is missing.");
    return null;
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

/**
 * Polishes the update text using the Gemini 3 Flash model.
 */
export const polishUpdateText = async (rawText: string, taskTitle: string, currentStatus: string): Promise<string> => {
  const ai = getAIClient();
  if (!ai) return rawText;

  try {
    const prompt = `
      You are a professional project manager assistant. 
      Rewrite the following status update note for the task "${taskTitle}" (Current Status: ${currentStatus}).
      Make it concise, professional, and clear. 
      Keep it under 3 sentences if possible.

      Raw Note: "${rawText}"
    `;

    // Using ai.models.generateContent directly with model and prompt as per guidelines
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    // .text is a property, not a method
    return response.text?.trim() || rawText;
  } catch (error) {
    console.error("Error calling Gemini:", error);
    return rawText;
  }
};

/**
 * Handles multi-turn chat interactions with the AI assistant.
 */
export const chatWithAI = async (
  history: {role: string, parts: {text: string}[]}[],
  message: string,
  systemInstruction?: string
): Promise<string> => {
  const ai = getAIClient();
  if (!ai) return "AI Service Unavailable. Please check configuration.";

  try {
    // Correctly setup chat session with model, history, and optional systemInstruction in config
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      history: history,
      config: systemInstruction ? { systemInstruction } : undefined
    });

    const result = await chat.sendMessage({ message });
    // .text is a property, not a method
    return result.text || "I didn't get a response.";
  } catch (error) {
    console.error("Chat Error", error);
    return "I'm having trouble connecting right now. Please try again.";
  }
};

/**
 * Extracts task details from a voice recording provided as base64 audio.
 */
export const createTaskFromVoice = async (audioBase64: string, mimeType: string): Promise<{title: string, category: string, status: string, targetDate: string} | null> => {
  const ai = getAIClient();
  if (!ai) return null;

  // Use local date for prompt context to avoid UTC shifts
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  const today = `${year}-${month}-${day}`;

  const categoriesList = CATEGORIES.join(', ');
  const statusesList = STATUSES.join(', ');

  const prompt = `
    You are a task management assistant.
    The user will provide a voice command to create a new task.
    The expected format usually contains: Category, Title, Target Date, and Status.

    Current Date: ${today}
    Allowed Categories: ${categoriesList} (Default to 'PERSONAL' if unclear).
    Allowed Statuses: ${statusesList} (Default to 'NOT_YET' if unclear).

    Extract the task details and return a JSON object.

    If the user doesn't specify a field, infer it logically or use the default.
  `;

  try {
    // Configure responseSchema for reliable JSON parsing of the extracted task details
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { text: prompt },
          {
            inlineData: {
              mimeType: mimeType,
              data: audioBase64
            }
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING, description: 'The title of the task' },
            category: { type: Type.STRING, description: 'One of the allowed categories' },
            targetDate: { type: Type.STRING, description: 'YYYY-MM-DD format' },
            status: { type: Type.STRING, description: 'One of the allowed statuses' }
          },
          required: ["title", "category", "targetDate", "status"]
        }
      }
    });

    // .text is a property, not a method
    const text = response.text;
    if (!text) return null;
    return JSON.parse(text);
  } catch (error) {
    console.error("Error calling Gemini for voice task:", error);
    return null;
  }
};

import { Task, TaskUpdate, TaskStatus, User, UserRole } from '../types';
import { supabase } from './supabaseClient';

const CURRENT_USER_KEY = 'dailypulse_current_user_id';

// --- AUTH SERVICE ---

/**
 * Fetches all registered users and their team memberships.
 */
export const getUsers = async (): Promise<User[]> => {
  const { data, error } = await supabase
    .from('users')
    .select('*');

  const usersRaw = data as any[] | null;
  if (error || !usersRaw) return [];

  // For each user, fetch their team members
  const usersWithTeams = await Promise.all(usersRaw.map(async (u: any) => {
    const { data: teamData } = await supabase
      .from('team_memberships')
      .select('member_id')
      .eq('admin_id', u.id);

    const team = teamData as any[] | null;
    return {
      id: u.id,
      username: u.username,
      pin: u.pin,
      role: u.role as UserRole,
      teamMemberIds: team ? team.map((t: any) => t.member_id) : []
    };
  }));

  return usersWithTeams;
};

export const registerUser = async (username: string, pin: string, role: UserRole): Promise<User | null> => {
  // Check if user already exists
  const { data: existing } = await supabase
    .from('users')
    .select('id')
    .ilike('username', username)
    .single();

  if (existing) return null;

  const newUser = {
    id: Date.now().toString(),
    username,
    pin,
    role
  };

  const { error } = await supabase.from('users').insert(newUser);

  if (error) {
    console.error("Register Error", error);
    return null;
  }

  return { ...newUser, teamMemberIds: [] };
};

export const loginUser = async (username: string, pin: string): Promise<User | null> => {
  const { data: user, error } = await supabase
    .from('users')
    .select('*')
    .ilike('username', username)
    .eq('pin', pin)
    .single();

  if (error || !user) return null;

  // Fetch associated team members
  const { data: teamData } = await supabase
    .from('team_memberships')
    .select('member_id')
    .eq('admin_id', user.id);

  const team = teamData as any[] | null;
  const fullUser: User = {
    id: user.id,
    username: user.username,
    pin: user.pin,
    role: user.role as UserRole,
    teamMemberIds: team ? team.map((t: any) => t.member_id) : []
  };

  localStorage.setItem(CURRENT_USER_KEY, fullUser.id);
  return fullUser;
};

export const getCurrentUser = async (): Promise<User | null> => {
  const id = localStorage.getItem(CURRENT_USER_KEY);
  if (!id) return null;

  const { data: user, error } = await supabase
    .from('users')
    .select('*')
    .eq('id', id)
    .single();

  if (error || !user) return null;

   // Fetch associated team members
   const { data: teamData } = await supabase
   .from('team_memberships')
   .select('member_id')
   .eq('admin_id', user.id);

  const team = teamData as any[] | null;
  return {
    id: user.id,
    username: user.username,
    pin: user.pin,
    role: user.role as UserRole,
    teamMemberIds: team ? team.map((t: any) => t.member_id) : []
  };
};

export const updateUser = async (updatedUser: User): Promise<boolean> => {
  const { error } = await supabase
    .from('users')
    .update({ pin: updatedUser.pin })
    .eq('id', updatedUser.id);

  return !error;
};

export const logoutUser = () => {
  localStorage.removeItem(CURRENT_USER_KEY);
};

export const addTeamMembers = async (adminId: string, memberIds: string[]): Promise<boolean> => {
  const inserts = memberIds.map(mid => ({
    admin_id: adminId,
    member_id: mid
  }));

  const { error } = await supabase.from('team_memberships').upsert(inserts, { onConflict: 'admin_id,member_id' });
  return !error;
};

