  const updatesRaw = data as any[] | null;
  if (error || !updatesRaw) return [];

  return updatesRaw.map((u: any) => ({
    id: u.id,
    taskId: u.task_id,
    date: u.date,
    content: u.content,
    timestamp: parseInt(u.timestamp),
