                       </div>
                    </div>

                    {/* PIN Update Section */}
                    <div className="bg-white p-6 rounded-2xl shadow-sm border border-stone-200 mb-6">
                       <h3 className="font-bold text-stone-700 mb-4 flex items-center gap-2"><Lock size={16}/> Update PIN</h3>
                       <div className="flex flex-col gap-4">
                          <div>
                            <label className="text-xs font-bold text-stone-400 uppercase ml-1 mb-1 block">New PIN</label>
                            <input 
                               type="password" 
                               value={newPin}
                               onChange={e => setNewPin(e.target.value)}
                               placeholder="Enter new PIN"
                               className="w-full px-4 py-3 bg-stone-50 border border-stone-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-primary/50 text-secondary tracking-widest"
                            />
                          </div>
                          <div>
                            <label className="text-xs font-bold text-stone-400 uppercase ml-1 mb-1 block">Confirm PIN</label>
                            <input 
                               type="password" 
                               value={confirmPin}
                               onChange={e => setConfirmPin(e.target.value)}
                               placeholder="Confirm new PIN"
                               className="w-full px-4 py-3 bg-stone-50 border border-stone-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-primary/50 text-secondary tracking-widest"
                            />
                          </div>

                          {profileMessage && (
                            <div className={`text-xs font-bold p-3 rounded-lg flex items-center gap-2 ${profileMessage.type === 'success' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                               {profileMessage.type === 'success' ? <CheckCircle2 size={14} /> : <AlertCircle size={14} />}
                               {profileMessage.text}
                            </div>
                          )}

                          <button onClick={handleUpdateProfile} className="bg-secondary text-accent font-bold py-3 rounded-xl hover:bg-stone-800 transition-colors shadow-lg shadow-stone-200 mt-2">
                             Update PIN
                          </button>
                       </div>
                    </div>

                    {/* Admin Actions */}
                    {currentUser.role === 'ADMIN' && (
                       <div className="bg-stone-100 border border-stone-200 p-6 rounded-2xl flex items-center justify-between">
                          <div>
                             <h3 className="font-bold text-secondary">Team Management</h3>
                             <p className="text-xs text-stone-500 font-medium">Add or remove members from your reporting line.</p>
                          </div>
                          <button onClick={() => setShowTeamModal(true)} className="bg-white border border-stone-200 hover:bg-stone-50 text-secondary p-3 rounded-xl shadow-sm transition-colors">
                             <Users size={20} />
                          </button>
                       </div>
                    )}
                 </div>
              </div>
            ) : selectedTask ? (
              // --- TASK DETAIL VIEW ---
              <>
                {/* Input Side */}
                <div className="flex-1 md:w-1/2 p-4 md:p-8 flex flex-col bg-white border-b md:border-b-0 md:border-r border-stone-200 overflow-y-auto animate-fade-in">
                   <div className="flex flex-col mb-4 md:mb-6">
                        <div className="flex items-center justify-between mb-3 gap-2">
                            <input 
                              type="text" 
                              value={selectedTask.title}
                              onChange={(e) => handleTaskChange('title', e.target.value)}
                              className="text-xl md:text-2xl font-bold text-secondary focus:outline-none focus:underline decoration-primary decoration-2 underline-offset-4 bg-transparent flex-1 min-w-0"
                            />
                            <button onClick={handleDeleteTask} className="p-2 bg-stone-100 hover:bg-red-50 text-stone-400 hover:text-red-600 rounded-full transition-colors shrink-0" title="Delete Task">
                                <Trash2 size={20} />
                            </button>
                        </div>

                        <div className="flex flex-wrap items-center gap-2 md:gap-3">
                          <div className="relative group">
                            <input 
                              list="category-list"
                              type="text"
                              value={selectedTask.category}
                              onChange={(e) => handleTaskChange('category', e.target.value)}
                              className="text-xs font-bold text-stone-600 bg-stone-50 border border-stone-200 rounded-lg px-2 py-1.5 w-24 md:w-32 hover:border-primary focus:border-primary outline-none transition-all"
                            />
                            <datalist id="category-list">
                              {allCategories.map(c => <option key={c} value={c} />)}
                            </datalist>
                          </div>

                          <select 
                            value={selectedTask.status}
                            onChange={(e) => handleTaskChange('status', e.target.value)}
                            className="text-xs font-bold text-stone-600 bg-stone-50 border border-stone-200 rounded-lg px-2 py-1.5 cursor-pointer hover:border-primary focus:border-primary outline-none transition-all"
                          >
                            {STATUSES.map(s => <option key={s} value={s}>{s.replace('_', ' ')}</option>)}
                          </select>

                          <div className="flex items-center gap-2 bg-stone-50 border border-stone-200 rounded-lg px-2 py-1 hover:border-primary transition-colors group">
                            <Calendar size={14} className="text-stone-400 group-hover:text-primary" />
                            <input 
                              type="date"
                              value={selectedTask.targetDate}
                              onChange={(e) => handleTaskChange('targetDate', e.target.value)}
                              className="text-xs font-mono text-stone-600 bg-transparent outline-none cursor-pointer w-24"
                            />
                          </div>

                          <div className="flex items-center gap-2 bg-accent/20 border border-stone-200 rounded-lg px-2 py-1 hover:border-primary transition-colors group">
                            <span className="text-[10px] font-bold text-stone-500 uppercase">Update:</span>
                            <Calendar size={14} className="text-stone-400 group-hover:text-primary" />
                            <input 
                                type="date" 
                                value={updateDate}
                                onChange={(e) => setUpdateDate(e.target.value)}
                                className="text-xs font-mono text-stone-600 bg-transparent outline-none cursor-pointer w-24"
                            />
                          </div>
                        </div>
                   </div>

                   <div className="flex flex-col gap-3 md:flex-1 min-h-0">
                     <div className="relative md:flex-1">
                        <textarea 
                          className="w-full h-20 md:h-full p-3 bg-stone-50 border border-stone-200 rounded-xl resize-none focus:outline-none focus:ring-2 focus:ring-primary/30 focus:bg-white transition-all text-sm leading-relaxed text-secondary placeholder:text-stone-400"
                          placeholder="Type your update here..."
                          value={updateContent}
                          onChange={e => setUpdateContent(e.target.value)}
                        />
                        {updateContent.length > 10 && (
                          <button 
                            onClick={handlePolish}
                            disabled={isPolishing}
                            className="absolute bottom-2 right-2 p-1.5 bg-white shadow-sm border border-stone-200 rounded-lg hover:bg-primary hover:text-secondary text-stone-500 transition-all hover:scale-105 disabled:opacity-50"
                          >
                            {isPolishing ? <div className="w-3 h-3 border-2 border-stone-600 border-t-transparent rounded-full animate-spin" /> : <Wand2 size={14} />}
                          </button>
                        )}
                     </div>
                   </div>

                   <div className="mt-4 flex justify-between items-center shrink-0">
                      {editUpdateId ? (
                        <div className="flex items-center gap-2">
                             <span className="text-xs text-amber-600 font-bold bg-amber-100 px-2 py-1 rounded hidden sm:inline">Editing</span>
                             <button onClick={handleCancelEdit} className="p-1 hover:bg-stone-100 rounded-full text-stone-400 hover:text-stone-600"><X size={14}/></button>
                        </div>
                      ) : <span />}
                      <button onClick={handleSaveUpdate} className="bg-secondary hover:bg-stone-800 text-accent px-6 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2 transition-transform active:scale-95 shadow-lg shadow-stone-200 w-full sm:w-auto justify-center" disabled={isSaving}>
                        {isSaving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />} 
                        {editUpdateId ? 'Update' : 'Save'}
                      </button>
                   </div>
                </div>

                {/* History Side */}
                <div className="flex-1 md:w-1/2 p-4 md:p-8 bg-stone-50 flex flex-col overflow-hidden min-h-[300px] md:min-h-0 animate-fade-in">
                  <div className="flex justify-between items-center mb-4 md:mb-6 shrink-0">
                    <h2 className="text-lg font-bold text-secondary">History</h2>
                    <div className="flex bg-white p-1 rounded-lg border border-stone-200">
                       <button 
                          onClick={() => setHistorySort(prev => prev === 'NEWEST' ? 'OLDEST' : 'NEWEST')}
                          className="px-3 py-1.5 text-xs font-bold rounded-lg bg-white border border-stone-100 hover:bg-stone-50 text-stone-600 flex items-center gap-1 transition-colors"
                       >
                           {historySort === 'OLDEST' ? <ArrowUp size={12}/> : <ArrowDown size={12}/>}
                           {historySort === 'OLDEST' ? 'Date Asc' : 'Date Desc'}
                       </button>
                    </div>
                  </div>

                  <div className="flex-1 overflow-y-auto pr-2 -mr-2 pb-20 md:pb-0">
                     {taskHistory.length === 0 ? (
                       <div className="flex flex-col items-center justify-center h-32 text-stone-400 mt-4">
                          <AlertCircle size={24} className="mb-2 opacity-30" />
                          <p className="text-sm">No updates yet.</p>
                       </div>
                     ) : (
                       taskHistory.map(update => (
                         <SwipeableCard 
                            key={update.id} 
                            update={update} 
                            onEdit={handleEditUpdateStart}
                            onCalendar={handleAddToCalendar}
                            onDelete={handleDeleteUpdate}
                         />
                       ))
                     )}
                  </div>
                </div>
              </>
            ) : (
              <div className="w-full h-full flex flex-col items-center justify-center text-stone-400 bg-stone-50/50 p-6 text-center animate-fade-in">
                <CheckCircle2 size={48} className="mb-4 opacity-20 text-primary" />
                <p className="text-lg font-bold text-stone-500">No Task Selected</p>
                <p className="text-sm opacity-60 mt-2">Select a task from the list to view details.</p>
                <button onClick={() => setActiveTab('overview')} className="mt-4 px-6 py-2 bg-white border border-stone-200 rounded-full text-sm font-bold text-primary shadow-sm md:hidden">Go to Overview</button>
              </div>
            )}
          </div>
      </div>

      {/* Mobile Nav */}
      <div className="h-16 bg-white border-t border-stone-200 flex md:hidden shrink-0 z-50 pb-safe">
         <button onClick={() => setActiveTab('overview')} className={`flex-1 flex flex-col items-center justify-center gap-1 ${activeTab === 'overview' ? 'text-primary' : 'text-stone-300'}`}>
            <LayoutList size={20} /> <span className="text-[10px] font-bold">Overview</span>
         </button>
         <button onClick={() => setActiveTab('updates')} className={`flex-1 flex flex-col items-center justify-center gap-1 ${activeTab === 'updates' ? 'text-primary' : 'text-stone-300'}`}>
            <History size={20} /> <span className="text-[10px] font-bold">Updates</span>
         </button>
         <button onClick={() => setActiveTab('detail')} className={`flex-1 flex flex-col items-center justify-center gap-1 ${activeTab === 'detail' ? 'text-primary' : 'text-stone-300'}`}>
            <FileText size={20} /> <span className="text-[10px] font-bold">Detail</span>
         </button>
         <button onClick={() => setActiveTab('chat')} className={`flex-1 flex flex-col items-center justify-center gap-1 ${activeTab === 'chat' ? 'text-primary' : 'text-stone-300'}`}>
            <MessageSquare size={20} /> <span className="text-[10px] font-bold">Chat</span>
         </button>
         <button onClick={() => setActiveTab('profile')} className={`flex-1 flex flex-col items-center justify-center gap-1 ${activeTab === 'profile' ? 'text-primary' : 'text-stone-300'}`}>
            <UserIcon size={20} /> <span className="text-[10px] font-bold">Profile</span>
         </button>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Plus, Search, Filter, Calendar, ChevronDown, Save, Wand2, AlertCircle, AlertTriangle, CheckCircle2, X, LayoutList, FileText, Mic, Loader2, MicOff, LogOut, Users, UserPlus, Shield, User as UserIcon, CheckSquare, Square, Settings, Lock, ArrowUpDown, ArrowUp, ArrowDown, MessageSquare, Send, Bot, Trash2, History, Layers, ArrowUpRight } from 'lucide-react';
import { Task, TaskUpdate, TaskStatus, FilterTime, SortOrder, User, UserRole } from './types';
import { STATUS_COLORS, CATEGORIES, STATUSES } from './constants';
import { getTasks, saveSingleTask, deleteTask, getUpdates, saveSingleUpdate, deleteUpdate, loginUser, registerUser, logoutUser, getCurrentUser, getUsers, addTeamMembers, updateUser } from './services/storageService';
import { polishUpdateText, createTaskFromVoice, chatWithAI } from './services/geminiService';
import SwipeableCard from './components/SwipeableCard';

type TaskSortOption = 'DATE_ASC' | 'DATE_DESC' | 'STATUS_ASC' | 'STATUS_DESC' | 'CATEGORY_ASC' | 'CATEGORY_DESC';

const App: React.FC = () => {
  // --- Auth State ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [authMode, setAuthMode] = useState<'LOGIN' | 'REGISTER'>('LOGIN');
  const [authUsername, setAuthUsername] = useState('');
  const [authPin, setAuthPin] = useState('');
  const [authRole, setAuthRole] = useState<UserRole>('MEMBER');
  const [authError, setAuthError] = useState('');
  const [authLoading, setAuthLoading] = useState(false);

  // --- App State ---
  const [tasks, setTasks] = useState<Task[]>([]);
  const [updates, setUpdates] = useState<TaskUpdate[]>([]);
  const [isLoadingData, setIsLoadingData] = useState(false);

  const [selectedTaskId, setSelectedTaskId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'overview' | 'detail' | 'profile' | 'chat' | 'updates'>('overview');

  // Filters & Sorting
  const [filterCategory, setFilterCategory] = useState<string>('ALL');
  const [filterStatus, setFilterStatus] = useState<string>('ACTIVE'); // Default to ACTIVE TASKS

  const [activeFilterDropdown, setActiveFilterDropdown] = useState<'SORT' | null>(null);

  const [filterTime, setFilterTime] = useState<FilterTime>('ALL');
  const [filterUser, setFilterUser] = useState<string>('ALL_TEAM'); 
  const [taskSort, setTaskSort] = useState<TaskSortOption>('DATE_ASC');
  const [searchQuery, setSearchQuery] = useState('');

  // Team Management State
  const [showTeamModal, setShowTeamModal] = useState(false);
  const [selectedTeamMemberIds, setSelectedTeamMemberIds] = useState<string[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]); // Cache for users

  // Admin Confirmation State
  const [showAdminConfirmModal, setShowAdminConfirmModal] = useState(false);

  // Helper for Local Date String (YYYY-MM-DD)
  const getLocalDate = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  // Detail View State
  const [updateDate, setUpdateDate] = useState<string>(getLocalDate());
  const [updateContent, setUpdateContent] = useState('');
  const [isPolishing, setIsPolishing] = useState(false);
  const [historySort, setHistorySort] = useState<SortOrder>('NEWEST');
  const [editUpdateId, setEditUpdateId] = useState<string | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  // Profile View State
  const [newPin, setNewPin] = useState('');
  const [confirmPin, setConfirmPin] = useState('');
  const [profileMessage, setProfileMessage] = useState<{type: 'success'|'error', text: string} | null>(null);

  // Chat State
  const [chatMessages, setChatMessages] = useState<{role: 'user' | 'model', text: string}[]>([
     { role: 'model', text: "Hi! I'm your AI assistant. I can answer questions about your tasks and team updates." }
  ]);
  const [chatInput, setChatInput] = useState('');
  const [isChatLoading, setIsChatLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const [lastStatus, setLastStatus] = useState<TaskStatus>(TaskStatus.NOT_YET);

  // Voice Recorder State
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessingVoice, setIsProcessingVoice] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);

  // --- Initialization ---

  useEffect(() => {
    // Check for logged in user
    const checkUser = async () => {
        const user = await getCurrentUser();
        if (user) {
          setCurrentUser(user);
          loadData();
        }
    };
    checkUser();
  }, []);

  useEffect(() => {
    if (activeTab === 'chat') {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages, activeTab]);

  const loadData = async () => {
    setIsLoadingData(true);
    const [fetchedTasks, fetchedUpdates, fetchedUsers] = await Promise.all([
        getTasks(),
        getUpdates(),
        getUsers()
    ]);
    setTasks(fetchedTasks);
    setUpdates(fetchedUpdates);
    setAllUsers(fetchedUsers);
    setIsLoadingData(false);
  };

  // Reset form when switching tasks
  useEffect(() => {
    if (selectedTaskId) {
      setUpdateContent('');
      setUpdateDate(getLocalDate());
      setEditUpdateId(null);
      setIsPolishing(false);

      const t = tasks.find(x => x.id === selectedTaskId);
      if (t) {
        setLastStatus(t.status);
      }
    }
  }, [selectedTaskId]);

  // --- Auth Actions ---

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthLoading(true);
    const user = await loginUser(authUsername, authPin);
    if (user) {
      setCurrentUser(user);
      await loadData();
      setAuthError('');
      setAuthUsername('');
      setAuthPin('');
    } else {
      setAuthError('Invalid username or PIN');
    }
    setAuthLoading(false);
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (authPin.length < 4) {
      setAuthError('PIN must be at least 4 digits');
      return;
    }
    setAuthLoading(true);
    const user = await registerUser(authUsername, authPin, authRole);
    if (user) {
      setCurrentUser(user);
      await loadData();
      setAuthError('');
      setAuthUsername('');
      setAuthPin('');
    } else {
      setAuthError('Username already exists');
    }
    setAuthLoading(false);
  };

  const handleLogout = () => {
    logoutUser();
    setCurrentUser(null);
    setTasks([]);
    setUpdates([]);
    setSelectedTaskId(null);
    setActiveTab('overview');
    setFilterUser('ALL_TEAM');
  };

  const handleUpdateProfile = async () => {
    if (!currentUser) return;
    setProfileMessage(null);

    if (newPin.length < 4) {
      setProfileMessage({ type: 'error', text: 'PIN must be at least 4 digits.' });
      return;
    }
    if (newPin !== confirmPin) {
      setProfileMessage({ type: 'error', text: 'PINs do not match.' });
      return;
    }

    const updatedUser = { ...currentUser, pin: newPin };
    const success = await updateUser(updatedUser);

    if (success) {
      setCurrentUser(updatedUser);
      setProfileMessage({ type: 'success', text: 'PIN updated successfully!' });
      setNewPin('');
      setConfirmPin('');
    } else {
      setProfileMessage({ type: 'error', text: 'Failed to update profile.' });
    }
  };

  const handleToggleTeamMember = (userId: string) => {
    setSelectedTeamMemberIds(prev => 
      prev.includes(userId) ? prev.filter(id => id !== userId) : [...prev, userId]
    );
  };

  const handleAddSelectedMembers = async () => {
    if (!currentUser || currentUser.role !== 'ADMIN') return;
    if (selectedTeamMemberIds.length === 0) return;

    const success = await addTeamMembers(currentUser.id, selectedTeamMemberIds);
    if (success) {
      // Refresh current user data
      const updatedUser = await getCurrentUser();
      if (updatedUser) setCurrentUser(updatedUser);

      // Refresh all users list
      const u = await getUsers();
      setAllUsers(u);

      setSelectedTeamMemberIds([]);
      setShowTeamModal(false);
      alert(`${selectedTeamMemberIds.length} members added to your line!`);
    } else {
      alert('Failed to add members.');
    }
  };

  // --- Computed Data & Helpers ---

  const allCategories = useMemo(() => {
    const taskCategories = tasks.map(t => t.category);
    return Array.from(new Set([...CATEGORIES, ...taskCategories])).sort();
  }, [tasks]);

  const selectedTask = useMemo(() => 
    tasks.find(t => t.id === selectedTaskId), 
  [tasks, selectedTaskId]);

  const taskHistory = useMemo(() => {
    if (!selectedTaskId) return [];
    return updates
      .filter(u => u.taskId === selectedTaskId && !u.isArchived)
      .sort((a, b) => {
        return historySort === 'NEWEST' ? b.timestamp - a.timestamp : a.timestamp - b.timestamp;
      });
  }, [updates, selectedTaskId, historySort]);

  // Grouped Updates for the new "Updates" tab
  const groupedUpdatesByDate = useMemo(() => {
    if (!currentUser) return {};

    const groups: Record<string, Record<string, Record<string, TaskUpdate[]>>> = {};

    // Permission Filter: Similar to overview but for updates
    const relevantUpdates = updates.filter(u => {
        const task = tasks.find(t => t.id === u.taskId);
        if (!task) return false;
        if (currentUser.role === 'ADMIN') {
            return task.userId === currentUser.id || currentUser.teamMemberIds.includes(task.userId);
        }
        return task.userId === currentUser.id;
    });

    // Sort relevant updates by timestamp descending
    const sorted = [...relevantUpdates].sort((a, b) => b.timestamp - a.timestamp);

    sorted.forEach(u => {
      const task = tasks.find(t => t.id === u.taskId);
      if (!task) return;

      const dateKey = u.date;
      const taskTitle = task.title;
      // Determine status at the time of update or current task status
      const statusKey = u.statusChange ? u.statusChange.to : task.status;

      if (!groups[dateKey]) groups[dateKey] = {};
      if (!groups[dateKey][taskTitle]) groups[dateKey][taskTitle] = {};
      if (!groups[dateKey][taskTitle][statusKey]) groups[dateKey][taskTitle][statusKey] = [];

      groups[dateKey][taskTitle][statusKey].push(u);
    });

    return groups;
  }, [updates, tasks, currentUser]);

  // User Map for fast lookup (id -> User Object)
  const userMap = useMemo(() => {
    return allUsers.reduce((acc, user) => {
      acc[user.id] = user;
      return acc;
    }, {} as Record<string, User>);
  }, [allUsers]);

  // Build Context for Chatbot
  const buildChatContext = () => {
    if (!currentUser) return '';

    // 1. Identify accessible tasks based on role
    const accessibleTasks = tasks.filter(t => {
        if (currentUser.role === 'ADMIN') {
             // Admins see their own + team members
             return t.userId === currentUser.id || currentUser.teamMemberIds.includes(t.userId);
        }
        return t.userId === currentUser.id;
    });

    // 2. Format Tasks
    const taskContext = accessibleTasks.length > 0 
      ? accessibleTasks.map(t => {
          const ownerName = userMap[t.userId]?.username || 'Unknown';
          return `- Task: "${t.title}" (Status: ${t.status}, Due: ${t.targetDate}, Category: ${t.category}, Owner: ${ownerName})`;
        }).join('\n')
      : "No tasks found.";

    // 3. Format Updates (associated with accessible tasks)
    const accessibleTaskIds = new Set(accessibleTasks.map(t => t.id));
    const relevantUpdates = updates
        .filter(u => accessibleTaskIds.has(u.taskId))
        .sort((a, b) => b.timestamp - a.timestamp) // Newest first
        .slice(0, 50); // Limit context to recent 50 updates to save tokens

    const updatesContext = relevantUpdates.length > 0
      ? relevantUpdates.map(u => {
          const task = tasks.find(t => t.id === u.taskId);
          return `- Update for "${task?.title || 'Unknown Task'}": "${u.content}" (Date: ${u.date})`;
        }).join('\n')
      : "No recent updates found.";

    return `
      You are the DailyPulse AI Assistant.
      You have access to the following real-time data from the DailyPulse app.

      STRICTLY use ONLY the provided TASKS and UPDATES data to answer the user's questions. 
      Do not hallucinate or invent information not present in the data below.
      If the answer is not in the data, politely state that you cannot find that information in the current records.

      CURRENT CONTEXT:
      User: ${currentUser.username} (${currentUser.role})
      Date: ${getLocalDate()}

      TASKS DATA:
      ${taskContext}

      RECENT UPDATES DATA:
      ${updatesContext}
    `.trim();
  };

  // --- Chat Actions ---
  const handleSendChatMessage = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!chatInput.trim() || isChatLoading) return;

    const userMsg = chatInput;
    setChatInput('');
    setChatMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsChatLoading(true);

    // Prepare history for API
    const historyForSdk = chatMessages.map(msg => ({
      role: msg.role,
      parts: [{ text: msg.text }]
    }));

    // Build the system instruction with the latest data
    const systemInstruction = buildChatContext();

    const responseText = await chatWithAI(historyForSdk, userMsg, systemInstruction);

    setChatMessages(prev => [...prev, { role: 'model', text: responseText }]);
    setIsChatLoading(false);
  };

  // Team Members List (for Admin Filter)
  const teamMembers = useMemo(() => {
    if (!currentUser || currentUser.role !== 'ADMIN') return [];
    return currentUser.teamMemberIds
      .map(id => userMap[id])
      .filter(Boolean) as User[];
  }, [currentUser, userMap]); 

  // Available users to add (not me, not already in team)
  const availableUsersToAdd = useMemo(() => {
    if (!currentUser || currentUser.role !== 'ADMIN') return [];
    return allUsers.filter((u: User) => 
      u.id !== currentUser.id && 
      !currentUser.teamMemberIds.includes(u.id)
    );
  }, [currentUser, allUsers]);

  // --- Filtering & Sorting Logic ---
  const filteredTasks = useMemo(() => {
    if (!currentUser) return [];

    const now = new Date();
    now.setHours(0,0,0,0);

    // 1. Filter
    const filtered = tasks.filter(task => {
      // User Permission Filter
      let isVisible = false;
      if (currentUser.role === 'ADMIN') {
        if (filterUser === 'ME') {
          isVisible = task.userId === currentUser.id;
        } else if (filterUser === 'ALL_TEAM') {
          // Show Admin's tasks AND Team Members' tasks
          isVisible = task.userId === currentUser.id || currentUser.teamMemberIds.includes(task.userId);
        } else {
          // Specific user selected
          isVisible = task.userId === filterUser;
        }
      } else {
        // Regular Member sees only their own
        isVisible = task.userId === currentUser.id;
      }

      if (!isVisible) return false;

      // Standard Filters
      const matchesSearch = task.title.toLowerCase().includes(searchQuery.toLowerCase());

      // Single-select filters
      const matchesCategory = filterCategory === 'ALL' || task.category === filterCategory;

      // "Active" Filter Logic: not yet, progress, follow up and repetitive.
      const matchesStatus = 
        filterStatus === 'ALL' ? true :
        filterStatus === 'ACTIVE' ? [TaskStatus.NOT_YET, TaskStatus.PROGRESS, TaskStatus.FOLLOW_UP, TaskStatus.REPETITIVE].includes(task.status) :
        task.status === filterStatus;

      let matchesTime = true;

      // Parse target date relative to local time to avoid UTC shifts
      let targetTime = 0;
      try {
        const [ty, tm, td] = task.targetDate.split('-').map(Number);
        const target = new Date(ty, tm - 1, td);
        targetTime = target.getTime();
      } catch(e) {
        targetTime = new Date(task.targetDate).getTime();
      }

      const diffDays = (targetTime - now.getTime()) / (1000 * 3600 * 24);

      if (filterTime === 'OVERDUE') matchesTime = diffDays < -0.9; // Approximate for overdue logic
      else if (filterTime === 'TODAY') matchesTime = diffDays >= -0.9 && diffDays <= 0.9;
      else if (filterTime === 'THIS_WEEK') matchesTime = diffDays >= -0.9 && diffDays <= 7;
      else if (filterTime === 'FUTURE') matchesTime = diffDays > 7;

      return matchesSearch && matchesCategory && matchesStatus && matchesTime;
    });

    // 2. Sort
    return filtered.sort((a, b) => {
        const getT = (dStr: string) => {
            try {
               const [y, m, d] = dStr.split('-').map(Number);
               return new Date(y, m-1, d).getTime();
            } catch { return 0; }
        };

        switch (taskSort) {
            case 'DATE_ASC':
                return getT(a.targetDate) - getT(b.targetDate);
            case 'DATE_DESC':
                return getT(b.targetDate) - getT(a.targetDate);
            case 'STATUS_ASC':
                return STATUSES.indexOf(a.status) - STATUSES.indexOf(b.status);
            case 'STATUS_DESC':
                return STATUSES.indexOf(b.status) - STATUSES.indexOf(a.status);
            case 'CATEGORY_ASC':
                return a.category.localeCompare(b.category);
            case 'CATEGORY_DESC':
                return b.category.localeCompare(a.category);
            default:
                return 0;
        }
    });

  }, [tasks, searchQuery, filterCategory, filterStatus, filterTime, filterUser, currentUser, taskSort]);

  // --- Helper Functions ---
  const formatListDate = (dateStr: string) => {
    if (!dateStr) return '';
    try {
      const [year, month, day] = dateStr.split('-').map(Number);
      const date = new Date(year, month - 1, day);
      if (isNaN(date.getTime())) return dateStr;

      const ddd = date.toLocaleDateString('en-US', { weekday: 'short' });
      const dd = day.toString().padStart(2, '0');
      const mmm = date.toLocaleDateString('en-US', { month: 'short' });
      const yy = year.toString().slice(-2);

      return `${ddd}, ${dd}-${mmm}-${yy}`;
    } catch (e) {
      return dateStr;
    }
  };

  // --- Actions ---

  const handleTaskSelect = (id: string) => {
    setSelectedTaskId(id);
    setActiveTab('detail');
  };

  const handleUpdateTransactionClick = (taskId: string) => {
    setSelectedTaskId(taskId);
    setActiveTab('detail');
  };

  const handleDeleteTask = async () => {
    if (!selectedTask) return;

    // Check if task has any updates associated with it (including archived ones)
    const hasHistory = updates.some(u => u.taskId === selectedTask.id);

    let confirmed = false;
    if (hasHistory) {
      confirmed = window.confirm("Are you sure? This task already has detail history?");
    } else {
      confirmed = window.confirm(`Are you sure you want to delete task "${selectedTask.title}"?`);
    }

    if (confirmed) {
       await deleteTask(selectedTask.id);
       // Remove from local state
       setTasks(prev => prev.filter(t => t.id !== selectedTask.id));
       // Also remove updates for this task from local state
       setUpdates(prev => prev.filter(u => u.taskId !== selectedTask.id));

       setSelectedTaskId(null);
       setActiveTab('overview');
    }
  };

  const handleSaveUpdate = async () => {
    if (!selectedTask || !updateContent.trim()) return;

    // Admin Check: If admin is updating another user's task
    if (currentUser?.role === 'ADMIN' && selectedTask.userId !== currentUser.id) {
      setShowAdminConfirmModal(true);
      return;
    }

    await executeSaveUpdate(false);
  };

  const handleConfirmAdminUpdate = async () => {
    setShowAdminConfirmModal(false);
    await executeSaveUpdate(true);
  };

  const executeSaveUpdate = async (isAdminOverride: boolean) => {
    if (!selectedTask || !updateContent.trim()) return;

    let finalContent = updateContent;
    if (isAdminOverride && currentUser) {
      finalContent = `${finalContent}\n(Updated by ${currentUser.username})`;
    }

    setIsSaving(true);

    // Check for status change
    let statusChangeData = undefined;
    if (lastStatus !== selectedTask.status) {
      statusChangeData = {
        from: lastStatus,
        to: selectedTask.status
      };

      // Update Task Status in DB
      const updatedTask = { ...selectedTask };
      setTasks(prev => prev.map(t => t.id === selectedTask.id ? updatedTask : t));
      await saveSingleTask(updatedTask);
    }

    if (editUpdateId) {
       const updatedUpdate = updates.find(u => u.id === editUpdateId);
       if (updatedUpdate) {
         const newUpdateObj = {
            ...updatedUpdate,
            content: finalContent,
            date: updateDate,
            statusChange: statusChangeData || updatedUpdate.statusChange
         };

         setUpdates(prev => prev.map(u => u.id === editUpdateId ? newUpdateObj : u));
         await saveSingleUpdate(newUpdateObj);
         setEditUpdateId(null);
       }
    } else {
      const newUpdate: TaskUpdate = {
        id: Date.now().toString(),
        taskId: selectedTask.id,
        date: updateDate,
        content: finalContent,
        timestamp: Date.now(),
        isArchived: false,
        statusChange: statusChangeData
      };
      setUpdates(prev => [newUpdate, ...prev]);
      await saveSingleUpdate(newUpdate);
    }

    if (statusChangeData) {
      setLastStatus(selectedTask.status);
    }

    setUpdateContent('');
    setUpdateDate(getLocalDate());
    setIsSaving(false);
  };

  const handleCancelEdit = () => {
    setEditUpdateId(null);
    setUpdateContent('');
    setUpdateDate(getLocalDate());
  };

  const handlePolish = async () => {
    if (!selectedTask || !updateContent.trim()) return;
    setIsPolishing(true);
    const polished = await polishUpdateText(updateContent, selectedTask.title, selectedTask.status);
    setUpdateContent(polished);
    setIsPolishing(false);
  };

  const handleTaskChange = async (field: keyof Task, value: any) => {
    if (!selectedTask) return;

    // Optimistic update
    const updatedTask = { ...selectedTask, [field]: value };
    setTasks(prev => prev.map(t => t.id === selectedTask.id ? updatedTask : t));

    // Save to DB (Debouncing would be better here in production, but simple save works)
    await saveSingleTask(updatedTask);
  };

  const handleAddToCalendar = (update: TaskUpdate) => {
    if (!selectedTask) return;
    const title = encodeURIComponent(`${selectedTask.title} - Update`);
    const details = encodeURIComponent(`Task: ${selectedTask.title}\nUpdate: ${update.content}`);
    const startDateStr = update.date.replace(/-/g, '');
    const dateObj = new Date(update.date);
    dateObj.setDate(dateObj.getDate() + 1);
    const endDateStr = dateObj.toISOString().split('T')[0].replace(/-/g, '');
    const dates = `${startDateStr}/${endDateStr}`;
    const url = `https://calendar.google.com/calendar/render?action=TEMPLATE&text=${title}&details=${details}&dates=${dates}`;
    window.open(url, '_blank');
  };

  const handleDeleteUpdate = async (update: TaskUpdate) => {
    setTimeout(async () => {
      if (window.confirm("Are you sure you want to delete this update?")) {
        setUpdates(prev => prev.filter(u => u.id !== update.id));
        await deleteUpdate(update.id);
        if (editUpdateId === update.id) {
          handleCancelEdit();
        }
      }
    }, 10);
  };

  const handleEditUpdateStart = (update: TaskUpdate) => {
    setUpdateContent(update.content);
    setUpdateDate(update.date);
    setEditUpdateId(update.id);
  };

  const createNewTask = async () => {
    if (!currentUser) return;
    const newTask: Task = {
      id: Date.now().toString(),
      userId: currentUser.id,
      title: 'New Task',
      category: CATEGORIES[0],
      status: TaskStatus.NOT_YET,
      targetDate: getLocalDate(),
      createdAt: Date.now()
    };

    setTasks([newTask, ...tasks]);
    setSelectedTaskId(newTask.id);
    setActiveTab('detail');
    setLastStatus(TaskStatus.NOT_YET);

    await saveSingleTask(newTask);
  };

  // Voice Recording
  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      let mimeType = 'audio/webm';
      if (!MediaRecorder.isTypeSupported(mimeType)) mimeType = 'audio/mp4';
      if (!MediaRecorder.isTypeSupported(mimeType)) mimeType = '';

      const recorder = mimeType ? new MediaRecorder(stream, { mimeType }) : new MediaRecorder(stream);
      const chunks: BlobPart[] = [];

      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunks.push(e.data); };
      recorder.onstop = async () => {
        const blob = new Blob(chunks, { type: recorder.mimeType });
        stream.getTracks().forEach(track => track.stop());
        const reader = new FileReader();
        reader.onloadend = async () => {
          const base64Data = (reader.result as string).split(',')[1];
          await processVoiceData(base64Data, recorder.mimeType || 'audio/webm');
        };
        reader.readAsDataURL(blob);
      };
      recorder.start();
      mediaRecorderRef.current = recorder;
      setIsRecording(true);
    } catch (error) {
      console.error(error);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsProcessingVoice(true);
    }
  };

  const processVoiceData = async (base64Data: string, mimeType: string) => {
    if (!currentUser) return;
    try {
      const result = await createTaskFromVoice(base64Data, mimeType);
      if (result) {
        const newTask: Task = {
          id: Date.now().toString(),
          userId: currentUser.id,
          title: result.title || 'New Voice Task',
          category: result.category || 'PERSONAL',
          status: (result.status as TaskStatus) || TaskStatus.NOT_YET,
          targetDate: result.targetDate || getLocalDate(),
          createdAt: Date.now()
        };
        setTasks(prev => [newTask, ...prev]);
        setSelectedTaskId(newTask.id);
        setActiveTab('detail');
        setLastStatus((result.status as TaskStatus) || TaskStatus.NOT_YET);

        await saveSingleTask(newTask);
      } else {
        alert("Could not understand voice command.");
      }
    } catch (error) {
      alert("Error processing voice command.");
    } finally {
      setIsProcessingVoice(false);
    }
  };

  const getDaysRemaining = (targetDate: string) => {
    let target: Date;
    try {
        const [y, m, d] = targetDate.split('-').map(Number);
        target = new Date(y, m - 1, d);
    } catch(e) {
        target = new Date(targetDate);
    }

    const today = new Date();
    today.setHours(0,0,0,0);
    // Use target date directly (it's already local midnight from the split)
    // Note: if target was created with new Date(y, m-1, d), it is at local 00:00:00.

    const diffTime = target.getTime() - today.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  };

  const getDaysLabel = (days: number) => {
    if (days < 0) return <span className="text-red-600 font-bold">{Math.abs(days)}d overdue</span>;
    if (days === 0) return <span className="text-amber-600 font-bold">Due Today</span>;
    return <span className="text-emerald-600">{days} days left</span>;
  };

  // --- RENDER ---

  // 1. AUTH SCREEN
  if (!currentUser) {
    return (
      <div className="flex h-[100dvh] w-full bg-beige items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-2xl shadow-xl overflow-hidden border border-stone-200">
           <div className="bg-accent p-8 text-center">
              <div className="w-16 h-16 bg-secondary text-accent rounded-2xl flex items-center justify-center text-2xl font-bold mx-auto mb-4 shadow-lg">DP</div>
              <h1 className="text-2xl font-bold text-secondary">DailyPulse</h1>
              <p className="text-secondary/80 font-medium uppercase tracking-tight">Daily Update Status</p>
           </div>

           <div className="p-8">
              <div className="flex bg-stone-100 p-1 rounded-xl mb-6">
                 <button 
                    onClick={() => { setAuthMode('LOGIN'); setAuthError(''); }}
                    className={`flex-1 py-2 text-sm font-bold rounded-lg transition-colors ${authMode === 'LOGIN' ? 'bg-white text-secondary shadow-sm' : 'text-stone-400'}`}
                 >
                    Login
                 </button>
                 <button 
                    onClick={() => { setAuthMode('REGISTER'); setAuthError(''); }}
                    className={`flex-1 py-2 text-sm font-bold rounded-lg transition-colors ${authMode === 'REGISTER' ? 'bg-white text-secondary shadow-sm' : 'text-stone-400'}`}
                 >
                    Register
                 </button>
              </div>

              <form onSubmit={authMode === 'LOGIN' ? handleLogin : handleRegister} className="flex flex-col gap-4">
                 <div>
                    <label className="text-xs font-bold text-stone-500 uppercase ml-1">Username</label>
                    <div className="relative mt-1">
                      <UserIcon size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
                      <input 
                        type="text" 
                        value={authUsername}
                        onChange={e => setAuthUsername(e.target.value)}
                        className="w-full pl-10 pr-4 py-3 bg-stone-50 border border-stone-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-primary/50 text-secondary font-medium"
                        placeholder="Enter username"
                        required
                        disabled={authLoading}
                      />
                    </div>
                 </div>

                 <div>
                    <label className="text-xs font-bold text-stone-500 uppercase ml-1">Pin Code</label>
                    <div className="relative mt-1">
                      <Shield size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
                      <input 
                        type="password" 
                        value={authPin}
                        onChange={e => setAuthPin(e.target.value)}
                        className="w-full pl-10 pr-4 py-3 bg-stone-50 border border-stone-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-primary/50 text-secondary font-medium tracking-widest"
                        placeholder="****"
                        required
                        disabled={authLoading}
                      />
                    </div>
                 </div>

                 {authMode === 'REGISTER' && (
                   <div>
                     <label className="text-xs font-bold text-stone-500 uppercase ml-1">Role</label>
                     <div className="flex gap-4 mt-2">
                        <label className="flex items-center gap-2 cursor-pointer">
                           <input type="radio" name="role" checked={authRole === 'MEMBER'} onChange={() => setAuthRole('MEMBER')} className="accent-secondary" />
                           <span className="text-sm font-bold text-stone-600">Member</span>
                        </label>
                        <label className="flex items-center gap-2 cursor-pointer">
                           <input type="radio" name="role" checked={authRole === 'ADMIN'} onChange={() => setAuthRole('ADMIN')} className="accent-secondary" />
                           <span className="text-sm font-bold text-stone-600">Admin</span>
                        </label>
                     </div>
                   </div>
                 )}

                 {authError && (
                   <div className="bg-red-50 text-red-600 text-xs font-bold p-3 rounded-xl flex items-center gap-2">
                     <AlertCircle size={14} /> {authError}
                   </div>
                 )}

                 <button 
                    type="submit" 
                    className="mt-4 bg-secondary text-accent py-3 rounded-xl font-bold hover:bg-stone-800 transition-transform active:scale-95 shadow-lg shadow-stone-200 flex justify-center items-center gap-2"
                    disabled={authLoading}
                 >
                    {authLoading ? <Loader2 size={18} className="animate-spin"/> : (authMode === 'LOGIN' ? 'Access Dashboard' : 'Create Account')}
                 </button>
              </form>
           </div>
        </div>
      </div>
    );
  }

  // 2. MAIN APP
  return (
    <div className="flex flex-col h-[100dvh] bg-beige overflow-hidden relative font-sans">

      {/* GLOBAL LOADING OVERLAY */}
      {isLoadingData && (
         <div className="absolute inset-0 z-[60] bg-white/50 backdrop-blur-sm flex items-center justify-center">
             <div className="bg-white p-4 rounded-xl shadow-xl flex items-center gap-3">
                 <Loader2 className="animate-spin text-primary" size={24} />
                 <span className="font-bold text-secondary">Loading Data...</span>
             </div>
         </div>
      )}

      {/* ADMIN CONFIRMATION MODAL */}
      {showAdminConfirmModal && (
        <div className="absolute inset-0 z-[80] bg-secondary/60 backdrop-blur-sm flex items-center justify-center p-6">
           <div className="bg-white rounded-2xl w-full max-w-sm p-6 shadow-2xl animate-in zoom-in-95 duration-200">
              <div className="w-12 h-12 bg-amber-100 rounded-full flex items-center justify-center mb-4 mx-auto text-amber-600">
                 <AlertTriangle size={24} />
              </div>

              <h3 className="text-lg font-bold text-secondary text-center mb-2">Confirm Update</h3>
              <p className="text-stone-500 text-sm text-center mb-6">
                Are you sure? This task is not yours. Your update will be tagged with your username.
              </p>

              <div className="flex gap-3">
                 <button 
                    onClick={() => setShowAdminConfirmModal(false)}
                    className="flex-1 py-3 text-sm font-bold text-stone-500 bg-stone-100 hover:bg-stone-200 rounded-xl transition-colors"
                 >
                    Cancel
                 </button>
                 <button 
                    onClick={handleConfirmAdminUpdate}
                    className="flex-1 py-3 text-sm font-bold text-white bg-secondary hover:bg-black rounded-xl transition-colors shadow-lg"
                 >
                    Confirm Update
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* TEAM MODAL */}
      {showTeamModal && (
        <div className="absolute inset-0 z-50 bg-secondary/50 backdrop-blur-sm flex items-center justify-center p-4">
           <div className="bg-white rounded-2xl w-full max-w-sm p-6 shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[80vh]">
              <div className="flex justify-between items-center mb-4 shrink-0">
                 <h3 className="text-lg font-bold text-secondary">Add Line Members</h3>
                 <button onClick={() => { setShowTeamModal(false); setSelectedTeamMemberIds([]); }} className="p-1 hover:bg-stone-100 rounded-full"><X size={20}/></button>
              </div>
              <p className="text-stone-500 text-sm mb-4 shrink-0">Select users to add to your reporting line.</p>

              <div className="flex-1 overflow-y-auto mb-4 border border-stone-200 rounded-xl min-h-[150px]">
                {availableUsersToAdd.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-stone-400 p-4">
                    <Users size={32} className="mb-2 opacity-30" />
                    <p className="text-sm text-center">No other members available to add.</p>
                  </div>
                ) : (
                  <div className="divide-y divide-stone-100">
                    {availableUsersToAdd.map(user => (
                      <label key={user.id} className="flex items-center p-3 hover:bg-stone-50 cursor-pointer group transition-colors">
                        <div className="relative flex items-center justify-center mr-3">
                           <input 
                             type="checkbox" 
                             checked={selectedTeamMemberIds.includes(user.id)}
                             onChange={() => handleToggleTeamMember(user.id)}
                             className="peer appearance-none w-5 h-5 border-2 border-stone-300 rounded checked:bg-primary checked:border-primary transition-all"
                           />
                           <CheckSquare size={14} className="absolute text-secondary opacity-0 peer-checked:opacity-100 pointer-events-none transform scale-0 peer-checked:scale-100 transition-transform" />
                        </div>
                        <div className="flex-1">
                           <div className="font-bold text-stone-700">{user.username}</div>
                           <div className="text-[10px] font-bold text-stone-400 uppercase">{user.role}</div>
                        </div>
                      </label>
                    ))}
                  </div>
                )}
              </div>

              <div className="flex gap-2 shrink-0">
                 <button onClick={() => { setShowTeamModal(false); setSelectedTeamMemberIds([]); }} className="flex-1 py-3 font-bold text-stone-500 hover:bg-stone-50 rounded-xl">Cancel</button>
                 <button 
                    onClick={handleAddSelectedMembers} 
                    disabled={selectedTeamMemberIds.length === 0}
                    className="flex-1 py-3 bg-secondary text-accent font-bold rounded-xl hover:bg-stone-800 disabled:opacity-50 disabled:cursor-not-allowed transition-all active:scale-95"
                 >
                    Add Selected ({selectedTeamMemberIds.length})
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* VOICE OVERLAY */}
      {(isRecording || isProcessingVoice) && (
        <div className="absolute inset-0 z-50 bg-secondary/90 flex flex-col items-center justify-center backdrop-blur-sm">
          {isRecording ? (
             <>
              <div className="w-24 h-24 bg-red-500 rounded-full flex items-center justify-center mb-8 animate-pulse shadow-[0_0_30px_rgba(239,68,68,0.6)]">
                <Mic size={48} className="text-white" />
              </div>
              <p className="text-white text-lg font-medium mb-2">Listening...</p>
              <button onClick={stopRecording} className="bg-white text-secondary px-8 py-3 rounded-full font-bold flex items-center gap-2 mt-4 hover:bg-stone-100 transition-colors">
                <MicOff size={20} /> Stop & Create
              </button>
             </>
          ) : (
             <>
              <Loader2 size={48} className="text-primary animate-spin mb-6" />
              <p className="text-white text-lg font-medium">Creating Task...</p>
             </>
          )}
        </div>
      )}

      {/* MAIN CONTENT WRAPPER */}
      <div className="flex-1 relative overflow-hidden flex flex-col md:block">

          {/* OVERVIEW SECTION (Header + List) */}
          <div className={`
              flex-col bg-beige border-b border-stone-200 min-h-0
              ${activeTab === 'overview' ? 'flex flex-1 animate-fade-in' : 'hidden md:flex'}
              md:relative md:h-1/2
          `}>
            {/* Top Bar */}
            <div className="h-16 flex items-center justify-between px-4 md:px-6 border-b border-stone-200 shrink-0 bg-beige">
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 bg-accent rounded-lg flex items-center justify-center text-secondary font-bold shadow-sm">DP</div>
                <div>
                  <h1 className="text-base md:text-xl font-bold text-secondary leading-tight uppercase">DAILY UPDATE STATUS</h1>
