                      <UserIcon size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
                      <input type="text" value={authUsername} onChange={e => setAuthUsername(e.target.value)} className="w-full pl-10 pr-4 py-3 bg-stone-50 border border-stone-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-primary/50 text-secondary font-medium" placeholder="Enter username" required disabled={authLoading} />
                    </div>
